@@ -1,0 +1,200 @@
+@page "/chat"
+@rendermode InteractiveServer
+@using sv_d840ffabbf754fb3813b8678c8c07f25.Services
+@using sv_d840ffabbf754fb3813b8678c8c07f25.Components.Chat
+@inject IChatService ChatService
+
+<PageTitle>Chat</PageTitle>
+
+<div class="chat-layout">
+    <div class="sidebar-col">
+        <ChannelSidebar Channels="channels"
+                        ActiveChannelId="selectedChannelId"
+                        OnChannelSelected="SelectChannel" />
+    </div>
+
+    <div class="main-col @(isThreadOpen ? "" : "expanded")">
+        @if (activeChannel is not null)
+        {
+            <div class="main-header">
+                <h3># @activeChannel.Name</h3>
+                <span class="header-desc">@activeChannel.Description</span>
+            </div>
+
+            <div class="message-list" @onscroll="HandleScroll" @ref="messageListRef">
+                @if (isLoadingMore)
+                {
+                    <div class="loading-indicator">Loading older messages…</div>
+                }
+                @foreach (var msg in messages)
+                {
+                    var threadInfo = threadSummaries.GetValueOrDefault(msg.Id);
+                    <MessageBubble Message="msg"
+                                   IsThreadStarter="threadInfo is not null"
+                                   ReplyCount="threadInfo?.ReplyCount ?? 0"
+                                   OnOpenThread="OpenThread"
+                                   OnReact="HandleReaction" />
+                }
+            </div>
+
+            <MessageInput Placeholder="Message #@activeChannel.Name"
+                          OnSend="SendMessage" />
+        }
+        else
+        {
+            <div class="empty-state">Select a channel to start chatting</div>
+        }
+    </div>
+
+    @if (isThreadOpen && threadRootMessage is not null)
+    {
+        <div class="thread-col">
+            <ThreadPanel RootMessage="threadRootMessage"
+                         ThreadMessages="threadMessages"
+                         OnClose="CloseThread"
+                         OnSendReply="SendThreadReply" />
+        </div>
+    }
+</div>
+
+@code {
+    private List<Channel> channels = [];
+    private List<Message> messages = [];
+    private Dictionary<int, ThreadSummary> threadSummaries = new();
+    private Channel? activeChannel;
+    private int selectedChannelId;
+
+    private bool isThreadOpen;
+    private int? threadRootId;
+    private Message? threadRootMessage;
+    private List<Message> threadMessages = [];
+
+    private bool isLoadingMore;
+    private bool hasMoreMessages = true;
+    private const int PageSize = 30;
+
+    private ElementReference messageListRef;
+
+    protected override async Task OnInitializedAsync()
+    {
+        channels = await ChatService.GetChannelsAsync();
+        if (channels.Count > 0)
+        {
+            await SelectChannel(channels[0]);
+        }
+    }
+
+    private async Task SelectChannel(Channel channel)
+    {
+        selectedChannelId = channel.Id;
+        activeChannel = channel;
+        messages = [];
+        threadSummaries = new();
+        hasMoreMessages = true;
+
+        await LoadMessages();
+        await ChatService.MarkChannelReadAsync(channel.Id);
+
+        // Refresh channels to update unread counts
+        channels = await ChatService.GetChannelsAsync();
+    }
+
+    private async Task LoadMessages()
+    {
+        var newMessages = await ChatService.GetMessagesAsync(selectedChannelId, messages.Count, PageSize);
+        hasMoreMessages = newMessages.Count >= PageSize;
+
+        // Prepend older messages when paging, append on initial load
+        if (messages.Count > 0)
+        {
+            messages.InsertRange(0, newMessages);
+        }
+        else
+        {
+            messages = newMessages;
+        }
+
+        await BuildThreadSummaries();
+    }
+
+    private async Task BuildThreadSummaries()
+    {
+        // Identify messages that have replies (messages whose Id is referenced by ReplyToId)
+        var replyTargetIds = messages
+            .Where(m => m.ReplyToId.HasValue)
+            .Select(m => m.ReplyToId!.Value)
+            .Distinct()
+            .ToList();
+
+        foreach (var rootId in replyTargetIds)
+        {
+            if (!threadSummaries.ContainsKey(rootId))
+            {
+                var replies = messages.Where(m => m.ReplyToId == rootId).ToList();
+                threadSummaries[rootId] = new ThreadSummary(
+                    rootId,
+                    replies.Count,
+                    replies.Max(r => r.SentAt)
+                );
+            }
+        }
+    }
+
+    private async Task HandleScroll()
+    {
+        // Scroll-to-top triggers loading older messages
+        if (!isLoadingMore && hasMoreMessages)
+        {
+            isLoadingMore = true;
+            StateHasChanged();
+
+            await LoadMessages();
+
+            isLoadingMore = false;
+        }
+    }
+
+    private async Task SendMessage(string content)
+    {
+        if (activeChannel is null) return;
+        var msg = await ChatService.SendMessageAsync(activeChannel.Id, content, null);
+        messages.Add(msg);
+    }
+
+    private async Task OpenThread(int messageId)
+    {
+        threadRootId = messageId;
+        threadRootMessage = messages.FirstOrDefault(m => m.Id == messageId);
+        threadMessages = await ChatService.GetThreadAsync(messageId);
+        isThreadOpen = true;
+    }
+
+    private void CloseThread()
+    {
+        isThreadOpen = false;
+        threadRootId = null;
+        threadRootMessage = null;
+        threadMessages = [];
+    }
+
+    private async Task SendThreadReply(string content)
+    {
+        if (activeChannel is null || threadRootId is null) return;
+        var msg = await ChatService.SendMessageAsync(activeChannel.Id, content, threadRootId);
+        threadMessages.Add(msg);
+        messages.Add(msg);
+        await BuildThreadSummaries();
+    }
+
+    private async Task HandleReaction(MessageBubble.ReactionRequest request)
+    {
+        await ChatService.AddReactionAsync(request.MessageId, request.Emoji);
+
+        // Refresh messages to reflect updated reactions
+        if (activeChannel is not null)
+        {
+            messages = await ChatService.GetMessagesAsync(activeChannel.Id, 0, messages.Count);
+        }
+    }
+}
+

toolArgs.file_text:
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}

.sidebar-col {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.main-col {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
    background: #fff;
}

.main-col.expanded {
    /* Takes remaining space when thread is closed */
}

.thread-col {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

.main-header {
    display: flex;
    align-items: baseline;
    gap: 12px;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    background: #fff;
    flex-shrink: 0;
}

.main-header h3 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    white-space: nowrap;
}

.header-desc {
    font-size: 0.85rem;
    color: #888;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    font-size: 0.8rem;
    color: #999;
}

.empty-state {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #999;
    font-size: 1.1rem;
}

